external_knowledge:
- "stormy seas of high-risk" refers to 'high' risk_level;
- "choppy waters of medium-risk" refers to 'medium' risk_level;
- "still sailing" implies the user is active (is_active = 1);
- "storm warnings" is a metaphor for alerts;
- "more than one tempest" indicates a COUNT(alert_id) > 1.

sql:
SELECT AVG(net_worth) AS average_net_worth
FROM assets
WHERE asset_type = 'bond' AND is_active = 1;

SELECT a.title, ra.risk_level
FROM assets a
JOIN risk_assessments ra ON a.asset_id = ra.asset_id;

external_knowledge:
- 'particularly attractive in terms of dividends' indicates a dividend yield above 5%; 
- 'high price-to-value ratio' means a p_vp above 1.5; 
- 'quite liquid' implies daily liquidity exceeding 100.

sql:
SELECT COUNT(t.transaction_id) AS transaction_count
FROM transactions t
JOIN portfolio_assets pa ON t.portfolio_asset_id = pa.portfolio_asset_id;

SELECT alert_id, user_id, asset_id, alert_type, threshold, created_at, last_triggered, status
FROM alerts
WHERE user_id = 0;

SELECT title 
FROM assets 
WHERE asset_id IN (SELECT asset_id FROM alerts WHERE status = 'disabled');
